import{f as a,ab as t,p as i,t as n}from"./chunks/framework.Bi8ho8sH.js";const u=JSON.parse('{"title":"FAQ","description":"This page list frequently asked questions on our Tingweek.","frontmatter":{"title":"FAQ","category":"Tingweek","permalink":"/govern-science/tingweek/faq","description":"This page list frequently asked questions on our Tingweek."},"headers":[],"relativePath":"govern-science/tingweek/faq.md","filePath":"govern-science/tingweek/faq.md"}'),o={name:"govern-science/tingweek/faq.md"};function r(s,e,l,h,d,c){return t(),i("div",null,[...e[0]||(e[0]=[n('<h1 id="faq-tingweek" tabindex="-1">FAQ Tingweek <a class="header-anchor" href="#faq-tingweek" aria-label="Permalink to &quot;FAQ Tingweek&quot;">​</a></h1><p><strong>This page lists frequently asked questions related to the HUNT Cloud Tingweeks.</strong></p><nav class="table-of-contents"><ul><li><a href="#about">About</a><ul><li><a href="#why-tings">Why Tings?</a></li><li><a href="#is-this-an-assembly">Is this an assembly?</a></li></ul></li><li><a href="#participation">Participation</a><ul><li><a href="#who-can-attend">Who can attend?</a></li><li><a href="#how-do-i-get-my-invitation">How do I get my invitation?</a></li><li><a href="#where-do-we-meet">Where do we meet?</a></li></ul></li></ul></nav><h2 id="about" tabindex="-1">About <a class="header-anchor" href="#about" aria-label="Permalink to &quot;About&quot;">​</a></h2><h3 id="why-tings" tabindex="-1">Why Tings? <a class="header-anchor" href="#why-tings" aria-label="Permalink to &quot;Why Tings?&quot;">​</a></h3><p>The inspiration to appoint time to meet at regular intervals in a layered structure is drawn from the Old Norse <a href="https://en.wikipedia.org/wiki/Thing_(assembly)#Etymology" target="_blank" rel="noreferrer">ting</a> structures such as <a href="https://en.wikipedia.org/wiki/Frostating" target="_blank" rel="noreferrer">Frostating</a> here in Trøndelag were we are located. The intention is to ensure regular discussions on how we can together elevate data for a better world, including feedback on how to best adapt and evolve the scientific toolbox of HUNT Cloud to better support your scientific journey.</p><h3 id="is-this-an-assembly" tabindex="-1">Is this an assembly? <a class="header-anchor" href="#is-this-an-assembly" aria-label="Permalink to &quot;Is this an assembly?&quot;">​</a></h3><p>No. Our tings are not the same as a general assembly (generalforsamling) with binding decisions. As of today, our tings are to be seen as a gathering of people that both champion and dream up ideas on how to best utilize data for a better world. HUNT Cloud is owned by NTNU which has the full financial and compliance responsibilities for our services.</p><h2 id="participation" tabindex="-1">Participation <a class="header-anchor" href="#participation" aria-label="Permalink to &quot;Participation&quot;">​</a></h2><h3 id="who-can-attend" tabindex="-1">Who can attend? <a class="header-anchor" href="#who-can-attend" aria-label="Permalink to &quot;Who can attend?&quot;">​</a></h3><p>The Tings are open for all lab users and administrators in HUNT Cloud.</p><h3 id="how-do-i-get-my-invitation" tabindex="-1">How do I get my invitation? <a class="header-anchor" href="#how-do-i-get-my-invitation" aria-label="Permalink to &quot;How do I get my invitation?&quot;">​</a></h3><p>Ting invitations are sent as a calendar booking a few weeks before the Tingweek. Agenda and digital meeting links are forwarded on email before the Tings.</p><h3 id="where-do-we-meet" tabindex="-1">Where do we meet? <a class="header-anchor" href="#where-do-we-meet" aria-label="Permalink to &quot;Where do we meet?&quot;">​</a></h3><p>We will meet digitally on Zoom utilizing the NTNU subscription. Links will be forwarded on email and on Slack for the Labting and the data space ting.</p>',15)])])}const f=a(o,[["render",r]]);export{u as __pageData,f as default};
